  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Bithumb'ın Ortaklık Yapısındaki Değişim — Yüzde 34 Sınırının Etkisi</text>
  <g font-family="sans-serif">
    <text x="20" y="65" fill="#a1a1aa" font-size="13">Mevcut durum (Haziran 2026 itibarıyla)</text>
    <rect x="20" y="80" width="300" height="46" rx="8" fill="#f87171" opacity="0.85"/>
